import React, { useEffect, useState } from "react";
import socket from "../socket";
import "./GameStyle.css";

function Host() {
  const [gamePin, setGamePin] = useState("");
  const [players, setPlayers] = useState([]);
  const [leaderboard, setLeaderboard] = useState([]);

  useEffect(() => {
    socket.on("gameCreated", (data) => {
      const pin = data?.gamePin || data?.gameId || data;
      setGamePin(pin);
    });

    socket.on("playersUpdated", (data) => setPlayers(data || []));
    socket.on("playerJoined", (data) => setPlayers(data || []));
    socket.on("leaderboardUpdated", (data) => setLeaderboard(data || []));
    socket.on("leaderboard", (data) => setLeaderboard(data || []));
    socket.on("updateScores", (data) => setLeaderboard(data || []));

    return () => {
      socket.off("gameCreated");
      socket.off("playersUpdated");
      socket.off("playerJoined");
      socket.off("leaderboardUpdated");
      socket.off("leaderboard");
      socket.off("updateScores");
    };
  }, []);

  const createGame = () => {
    socket.emit("createGame");
  };

  const startGame = () => {
    if (!gamePin) {
      alert("Create game first");
      return;
    }
    socket.emit("startGame", gamePin);
  };

  return (
    <div className="host-wait-page">
      <div className="brand-top">Unpaid Education</div>

      {!gamePin ? (
        <div className="host-card">
          <h1>Unpaid Education</h1>
          <p>Host live quiz game</p>
          <button className="primary-btn" onClick={createGame}>
            Create Game
          </button>
        </div>
      ) : (
        <>
          <div className="pin-box">
            <p>Game PIN</p>
            <h1>{gamePin}</h1>
          </div>

          <h2 className="waiting-title">Players Joined</h2>

          <div className="players-grid">
            {(players || []).length === 0 ? (
              <p className="empty-text">Waiting for players...</p>
            ) : (
              (players || []).map((player, index) => (
                <div className="player-badge" key={index}>
                  🐝 {player.name || player.playerName || player}
                </div>
              ))
            )}
          </div>

          <button className="start-btn" onClick={startGame}>
            Start Game
          </button>

          <div className="mini-board">
            <h3>Live Leaderboard</h3>
            {(leaderboard || []).length === 0 ? (
              <p>No scores yet</p>
            ) : (
              leaderboard.map((p, i) => (
                <p key={i}>
                  #{i + 1} {p.name || p.playerName} - {p.score}
                </p>
              ))
            )}
          </div>
        </>
      )}
    </div>
  );
}

export default Host;
